1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block stable (still life)", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.length).toBe(4);
18	    expect(new Set(result.map(c => c.join(",")))).toEqual(
19	      new Set(block.map(c => c.join(",")))
20	    );
21	  });
22	  it("transforms an L-shape into a 2x2 block (reproduction)", () => {
23	    const lShape: Cell[] = [[0, 0], [1, 0], [0, 1]];
24	    const expected: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
25	    const result = nextGeneration(lShape);
26	    expect(new Set(result.map(c => c.join(",")))).toEqual(
27	      new Set(expected.map(c => c.join(",")))
28	    );
29	  });
30	  it("oscillates a vertical blinker to horizontal", () => {
31	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
32	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
33	    const result = nextGeneration(vertical);
34	    expect(new Set(result.map(c => c.join(",")))).toEqual(
35	      new Set(horizontal.map(c => c.join(",")))
36	    );
37	  });
38	  it("kills the center of a fully-surrounded cell (overpopulation)", () => {
39	    const fullSquare: Cell[] = [
40	      [0, 0], [1, 0], [2, 0],
41	      [0, 1], [1, 1], [2, 1],
42	      [0, 2], [1, 2], [2, 2],
43	    ];
44	    const result = nextGeneration(fullSquare);
45	    const resultKeys = new Set(result.map(c => c.join(",")));
46	    expect(resultKeys.has("1,1")).toBe(false);
47	  });
48	  it("handles cells at negative coordinates", () => {
49	    const negBlock: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
50	    const result = nextGeneration(negBlock);
51	    expect(new Set(result.map(c => c.join(",")))).toEqual(
52	      new Set(negBlock.map(c => c.join(",")))
